example.code:
# Generic class
class Stack[T]:
    def __init__(self) -> None:
        self._items: list[T] = []

    def push(self, item: T) -> None:
        self._items.append(item)

    def pop(self) -> T:
        return self._items.pop()

# Generic function
def first[T](items: list[T]) -> T | None:
    return items[0] if items else None

# Constrained TypeVar
class NumberBox[T: (int, float)]:
    def __init__(self, value: T) -> None:
        self.value = value

# Type alias (PEP 695)
type JSON = dict[str, "JSON"] | list["JSON"] | str | int | float | bool | None

from typing import TypeVar, Generic

T = TypeVar('T')

class Stack(Generic[T]):
    def __init__(self) -> None:
        self._items: list[T] = []

def process(value: int | str) -> None:
    ...

def get_user(user_id: int) -> dict | None:
    ...

def fallback(primary: str | None, secondary: str) -> str:
    return primary or secondary

from typing import TypeIs

def is_str(x: object) -> TypeIs[str]:
    return isinstance(x, str)

def process(x: int | str) -> None:
    if is_str(x):
        print(x.upper())  # x: str
    else:
        print(x + 1)      # x: int — narrowed by TypeIs

from typing import TypeGuard

def is_str(x: object) -> TypeGuard[str]:
    return isinstance(x, str)

def process(x: int | str) -> None:
    if is_str(x):
        print(x.upper())  # x: str
    else:
        print(x + 1)      # x: int | str — NOT narrowed!
        # Must add isinstance(x, int) in else branch
